import axios from 'axios';

const API_URL = 'http://localhost:5001/api';

// Create axios instance
const api = axios.create({
  baseURL: API_URL,
  headers: {
    'Content-Type': 'application/json'
  }
});

// Add token to requests if available
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// Auth API
export const authAPI = {
  signup: (userData) => api.post('/auth/signup', userData),
  login: (credentials) => api.post('/auth/login', credentials),
  getProfile: () => api.get('/auth/profile')
};

// Rides API
export const ridesAPI = {
  searchRides: (params) => api.get('/rides/search', { params }),
  createRide: (rideData) => api.post('/rides', rideData),
  getMyRides: () => api.get('/rides/my-rides'),
  bookRide: (rideId) => api.post(`/rides/${rideId}/book`),
  startRide: (rideId) => api.put(`/rides/${rideId}/start`),
  completeRide: (rideId) => api.put(`/rides/${rideId}/complete`),
  cancelRide: (rideId) => api.delete(`/rides/${rideId}`)
};

export default api;
